# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

# Define your rabbitmq server's IP address or hostname, and port
rabbitmq_server = "localhost"
port = 15672

def create_vhost(app_name):
    url = f"http://{rabbitmq_server}:{port}/api/vhosts/{app_name}"
    response = requests.put(url)
    if response.status_code == 201:
        print(f"Virtual host {app_name} created successfully")
    else:
        print(f"Failed to create virtual host {app_name}")

def delete_vhost(app_name):
    url = f"http://{rabbitmq_server}:{port}/api/vhosts/{app_name}"
    response = requests.delete(url)
    if response.status_code == 204:
        print(f"Virtual host {app_name} deleted successfully")
    else:
        print(f"Failed to delete virtual host {app_name}")

def create_user(app_name):
    user_id = app_name.lower()
    url = f"http://{rabbitmq_server}:{port}/api/users"
    data = {
        "name": user_id,
        "password_hashed": "AMQVPw==",  # This is an example password hash, generate a new one
        "permissions": [{"vhost": app_name}]
    }
    response = requests.put(url, headers={"Content-Type": "application/json"}, data=json.dumps(data))
    if response.status_code == 201:
        print(f"User {user_id} created successfully")
    else:
        print(f"Failed to create user {user_id}")

def delete_user(app_name):
    user_id = app_name.lower()
    url = f"http://{rabbitmq_server}:{port}/api/users/{user_id}"
    response = requests.delete(url)
    if response.status_code == 204:
        print(f"User {user_id} deleted successfully")
    else:
        print(f"Failed to delete user {user_id}")

def grant_permissions(app_name, username):
    url = f"http://{rabbitmq_server}:{port}/api/permissions"
    data = {
        "vhost": app_name,
        "user": username,
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    }
    response = requests.put(url, headers={"Content-Type": "application/json"}, data=json.dumps(data))
    if response.status_code == 201:
        print(f"Permissions granted to user {username} in virtual host {app_name}")
    else:
        print(f"Failed to grant permissions to user {username} in virtual host {app_name}")

# Define your applications' names
applications = ["app1", "app2", "app3"]

for app in applications:
    create_vhost(app)
    create_user(app)
    delete_vhost(app)  # You might want to uncomment this line to remove vhosts after users have been created